using Xunit;
using BogDb.Core.Processor.Operator;

namespace BogDb.Tests.Processor;

public class HashJoinPredicateTests
{
    // Emits one row per call, populating CurrentVariableIds with named variables.
    private class MockVariableOperator : PhysicalOperator
    {
        private readonly List<Dictionary<string, object?>> _rows;
        private int _position;

        public MockVariableOperator(IEnumerable<Dictionary<string, object?>> rows)
            : base(PhysicalOperatorType.SCAN_NODE_ID, 0)
        {
            _rows = rows.ToList();
            _position = 0;
        }

        public override bool GetNextTuple(BogDb.Core.Processor.ExecutionContext context)
        {
            if (_position < _rows.Count)
            {
                context.CurrentVariableIds = new Dictionary<string, object?>(_rows[_position]);
                if (_rows[_position].TryGetValue("id", out var idVal) && idVal is long id)
                    context.CurrentNodeId = id;
                _position++;
                return true;
            }
            return false;
        }
    }

    [Fact]
    public void ValueHashJoin_PathTraversal_ResolvesCorrectly()
    {
        var probeChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 1L },
            new Dictionary<string, object?> { ["n"] = 2L },
            new Dictionary<string, object?> { ["n"] = 3L }
        });
        var buildChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 2L },
            new Dictionary<string, object?> { ["n"] = 3L },
            new Dictionary<string, object?> { ["n"] = 4L }
        });

        var hashJoin = new ValueHashJoin(probeChild, buildChild, new[] { "n" }, 100);
        var context = new BogDb.Core.Processor.ExecutionContext(null, null);

        var matched = 0;
        while (hashJoin.GetNextTuple(context))
            matched++;

        Assert.Equal(2, matched);
    }

