    [Fact]
    public void OptionalJoin_NoMatch_EmitsLeftRowWithNulls()
    {
        var leftChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 1L },
            new Dictionary<string, object?> { ["n"] = 2L }
        });
        var rightChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 2L, ["extra"] = "found" }
        });

        var optJoin = new OptionalJoin(leftChild, rightChild, new[] { "n" }, 200);
        var context = new BogDb.Core.Processor.ExecutionContext(null, null);

        var emitted = 0;
        while (optJoin.GetNextTuple(context))
            emitted++;

        // Both left rows should be emitted (n=1 with no match, n=2 with match)
        Assert.Equal(2, emitted);
    }

    [Fact]
    public void MarkJoin_SetsMarkCorrectly()
    {
        var probeChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 1L },
            new Dictionary<string, object?> { ["n"] = 2L },
            new Dictionary<string, object?> { ["n"] = 3L }
        });
        var buildChild = new MockVariableOperator(new[]
        {
            new Dictionary<string, object?> { ["n"] = 2L }
        });

        var markJoin = new MarkJoin(probeChild, buildChild, new[] { "n" }, "_exists", 300);
        var context = new BogDb.Core.Processor.ExecutionContext(null, null);

        var results = new List<(long id, bool mark)>();
        while (markJoin.GetNextTuple(context))
        {
            var id = (long)context.CurrentVariableIds!["n"]!;
            var mark = (bool)context.CurrentScalarBindings!["_exists"]!;
            results.Add((id, mark));
        }

        Assert.Equal(3, results.Count);
        Assert.False(results[0].mark); // n=1, no match
        Assert.True(results[1].mark);  // n=2, match exists
        Assert.False(results[2].mark); // n=3, no match
    }
